const data = $input.first().json;
const chunks = data.chunks || [];
const ragContext = chunks.length > 0
  ? chunks.map((c, i) => `[${i+1}] Fuente: ${c.documentTitle || 'Documento'}\nSección: ${c.sectionTitle || 'N/A'}\nContenido: ${c.content}\n`).join('\n---\n')
  : 'No se encontraron documentos relevantes en la base de conocimientos para esta consulta.';
const sources = [...new Set(chunks.map(c => c.documentTitle).filter(Boolean))];
return [{ json: { ...($('Extraer Datos').item.json), ragContext, sources, hasRagResults: chunks.length > 0 } }];

const agentOut = $('Agente IA').item.json.output || 'No pude procesar tu solicitud. Por favor, intenta de nuevo.';
const sources = $('Preparar Contexto RAG').item.json.sources || [];
const approxTokens = Math.ceil(agentOut.length / 3);
return [{ json: { response: agentOut, agentName: 'PsdAgent', sourcesCited: sources.length > 0 ? sources : null, tokenCount: approxTokens, modelUsed: 'claude-sonnet-4-6', costUsd: parseFloat((approxTokens / 1000000 * 3.0).toFixed(8)), latencyMs: 0 } }];
